-- Vivijure Studio -- PUBLIC DEMO STUDIO seed (#625). DEMO D1 ONLY. NEVER prod.
--
-- This file lives under migrations/demo/ ON PURPOSE: like migrations/manual/, a subdirectory is NOT
-- scanned by `wrangler d1 migrations apply`, so it can NEVER auto-apply to the production DB and
-- pollute the real catalog / project library. The public demo deploy (AUTH_MODE=demo, its own demo
-- D1, no AI/RunPod/dispatch/R2 bindings) applies it EXPLICITLY, AFTER the base schema:
--   wrangler d1 migrations apply <demo-db>            # base schema: migrations/0001..0010
--   wrangler d1 execute <demo-db> --file=migrations/demo/0001_demo_seed.sql
--
-- What it seeds:
--   1. installed_modules: the 26 in-repo module manifests, captured VERBATIM from each module worker
--      GET /module.json. DISPLAY-ONLY by construction -- the script_name is demo-seed-<name>, which no
--      dispatch namespace serves (the demo binds none), and AUTH_MODE=demo denies every mutation at the
--      gate, so nothing here is invocable. The registry reads these rows in demo mode (#625 exception in
--      discoverDispatchModules) so GET /api/modules projects the AUTHENTIC studio catalog with zero mock
--      workers. Re-capture on module drift (a future reseed follow-up).
--   2. Demo content: browseable projects, cast, and COMPLETED renders whose films are the public S23
--      showcase MP4s. The render output_key is an ABSOLUTE assets.skyphusion.net URL, so the demo needs
--      NO R2 binding; the render display consumes it verbatim (planner-history-row.js artifactUrl).
--
-- Idempotent: every statement is INSERT OR IGNORE, so a re-apply is a no-op.

-- ---------------------------------------------------------------------------
-- installed_modules: the captured real catalog (display-only; see header).
-- ---------------------------------------------------------------------------
INSERT OR IGNORE INTO installed_modules (name, script_name, manifest_json, api, installed_at, enabled) VALUES
