-- ---------------------------------------------------------------------------
-- Demo content: browseable projects, cast, and completed renders whose films
-- are the public S23 showcase MP4s (absolute URLs on assets.skyphusion.net, so
-- the demo needs NO R2 binding). High explicit ids (>=9000) keep the seed clear
-- of any real autoincrement rows. All INSERT OR IGNORE (idempotent re-apply).
-- ---------------------------------------------------------------------------

-- Projects (storyboard_projects): each carries a real storyboard so the planner resumes into it.
INSERT OR IGNORE INTO storyboard_projects (id, public_id, slug, name, prefs_json, last_storyboard_json) VALUES
