   '{"title":"NEON AFTERGLOW","duration_seconds":30,"clip_seconds":3,"style_prefix":"1080p anime cyberpunk, rain-slick neon streets, cel shading, dramatic rim light","use_characters":["A","B"],"scenes":[{"id":"shot_01","prompt":"A lone courier in a worn flight jacket steps off a maglev platform into neon rain, holograms flickering overhead","character_slots":["A"],"target_seconds":3},{"id":"shot_02","prompt":"Close on the courier eyes reflecting a scrolling wall of advertisements","character_slots":["A"],"target_seconds":3},{"id":"shot_03","prompt":"A masked broker leans against a ramen stall, steam curling between them","character_slots":["B"],"target_seconds":3},{"id":"shot_04","prompt":"The two figures face off across the wet alley as drones sweep past","character_slots":["A","B"],"target_seconds":3},{"id":"shot_05","prompt":"Wide shot of the city skyline as the courier sprints across a rooftop, sirens blooming below","character_slots":["A"],"target_seconds":3}]}'),
